easy.solution:
class Rectangle:
    def __init__(self, w, h):
        self.w = w
        self.h = h
    def area(self):
        return self.w * self.h

medium.solution:
class Counter:
    def __init__(self, init=0):
        self.val = init
    def inc(self): self.val += 1
    def dec(self): self.val -= 1
    def get_val(self): return self.val

hard.solution:
class Point3D:
    __slots__ = ['x', 'y', 'z']
    def __init__(self, x, y, z):
        self.x = x
        self.y = y
        self.z = z
